// submit.js — Part 4: Backend integration
import { useState } from 'react';
import { useStore } from './store';
import { shallow } from 'zustand/shallow';

const selector = (state) => ({ nodes: state.nodes, edges: state.edges });

export const SubmitButton = () => {
  const { nodes, edges } = useStore(selector, shallow);
  const [loading, setLoading]   = useState(false);
  const [result,  setResult]    = useState(null);
  const [show,    setShow]      = useState(false);

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const res = await fetch('http://localhost:8000/pipelines/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodes, edges }),
      });
      const data = await res.json();
      setResult(data);
      setShow(true);
      setTimeout(() => setShow(false), 5000);

      // Trigger browser alert displaying values of num_nodes, num_edges, and is_dag in a user-friendly manner
      alert(
        `Pipeline Analysis Results:\n` +
        `-----------------------------------------\n` +
        `• Total Nodes: ${data.num_nodes}\n` +
        `• Total Edges: ${data.num_edges}\n` +
        `• Directed Acyclic Graph (DAG): ${data.is_dag ? 'Yes (✓ Valid)' : 'No (✗ Contains Cycles)'}`
      );
    } catch (err) {
      setResult({ error: 'Could not connect to backend. Is the server running?' });
      setShow(true);
      setTimeout(() => setShow(false), 5000);
      alert('Error: Could not connect to the backend. Is the server running?');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div className="pf-submit-bar">
        <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>
          {nodes.length} node{nodes.length !== 1 ? 's' : ''} · {edges.length} edge{edges.length !== 1 ? 's' : ''}
        </span>
        <button className="pf-submit-btn" onClick={handleSubmit} disabled={loading}>
          {loading ? '⏳ Analysing...' : '▶ Run Pipeline'}
        </button>
      </div>

      {/* Result toast */}
      <div className={`pf-result-toast ${show ? 'show' : ''}`}>
        {result?.error ? (
          <span style={{ color: '#f87171', fontSize: 13 }}>{result.error}</span>
        ) : result && (
          <>
            <div className="pf-result-stat">
              <span className="pf-result-stat-value">{result.num_nodes}</span>
              <span className="pf-result-stat-label">Nodes</span>
            </div>
            <div className="pf-result-divider" />
            <div className="pf-result-stat">
              <span className="pf-result-stat-value">{result.num_edges}</span>
              <span className="pf-result-stat-label">Edges</span>
            </div>
            <div className="pf-result-divider" />
            <div className="pf-result-stat">
              <span className={`pf-dag-badge ${result.is_dag ? 'pf-dag-true' : 'pf-dag-false'}`}>
                {result.is_dag ? '✓ Valid DAG' : '✗ Has Cycles'}
              </span>
              <span className="pf-result-stat-label">Pipeline</span>
            </div>
          </>
        )}
        <button
          onClick={() => setShow(false)}
          style={{ marginLeft: 'auto', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: 16 }}
        >✕</button>
      </div>
    </>
  );
};
